def tokens(s):
    return s.split()

def token_f1(a, b):
    ta, tb = tokens(a), tokens(b)
    from collections import Counter
    ca, cb = Counter(ta), Counter(tb)
    common = sum((ca & cb).values())
    if common == 0:
        return 0.0, 0.0, 0.0
    precision = common / len(ta)
    recall = common / len(tb)
    if precision + recall == 0:
        f1 = 0.0
    else:
        f1 = 2*precision*recall/(precision+recall)
    return precision, recall, f1

def lcs_length(a, b):
    # dynamic programming LCS length
    # That's O(n*m), but strings small.
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = temp
    return dp[m]

def lcs_ratio(a, b):
    lcs = lcs_length(a, b)
    # normalized by max length or average; choose symmetric ratio
    denom = (len(a)+len(b))/2
    if denom == 0:
        return 0.0
    return lcs/denom

def lcs_ratio_candidate_length(a, b):
    lcs = lcs_length(a, b)
    return lcs/len(a) if len(a)>0 else 0.0

